const CollectionCommand=require("./services/collectionCommand");async function testCollectionCommand(){new CollectionCommand;try{console.log("🧪 Testing Collection Command..."),console.log("=".repeat(50));const testSlug=process.argv[2];if(!testSlug)return console.log("❌ Please provide a collection slug as argument"),console.log("Usage: node test-collection-command.js <collection-slug>"),void console.log("Example: node test-collection-command.js tiny-buds40x40");console.log(`🔍 Testing collection command for: ${testSlug}`),console.log("📍 Chain: Base (default)"),console.log(""),console.log("📊 Fetching collection info...");const nftTracker=new(require("./services/nftTracker")),collectionInfo=await nftTracker.getCollectionInfoBySlug(testSlug,"Base");collectionInfo?(console.log("✅ Collection info found:"),console.log(`   Name: ${collectionInfo.name}`),console.log(`   Description: ${collectionInfo.description||"N/A"}`),console.log(`   Twitter: ${collectionInfo.twitter_username||"N/A"}`),console.log(`   Discord: ${collectionInfo.discord_url||"N/A"}`),console.log(`   Website: ${collectionInfo.homepage_url||"N/A"}`)):console.log("❌ No collection info found"),console.log(""),console.log("📈 Fetching collection stats...");const stats=await nftTracker.getCollectionStatsBySlug(testSlug,"Base");stats?(console.log("✅ Collection stats found:"),console.log(`   Floor Price: ${stats.floor_price||"N/A"} ETH`),console.log(`   Total Volume: ${stats.total_volume||"N/A"} ETH`),console.log(`   Total Supply: ${stats.total_supply||"N/A"}`),console.log(`   Owners: ${stats.num_owners||"N/A"}`)):console.log("❌ No collection stats found"),console.log(""),console.log("💰 Fetching creator fees info...");const creatorFees=await nftTracker.getCollectionCreatorFees(testSlug,"Base");creatorFees?(console.log("✅ Creator fees info found:"),console.log("   Percentage: "+(null!==creatorFees.percentage?creatorFees.percentage+"%":"null")),console.log(`   Is Enforced: ${creatorFees.is_enforced}`),console.log(`   Is Optional: ${creatorFees.is_optional}`)):console.log("❌ No creator fees info found"),console.log(""),console.log("✅ Collection command test completed successfully!")}catch(error){console.error("❌ Error:",error)}finally{nftTracker&&"function"==typeof nftTracker.disconnect&&await nftTracker.disconnect(),process.exit(0)}}testCollectionCommand();